&lt;td&gt;936,468&lt;/td&gt;
&lt;td&gt;21,791,478&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;总输出 token&lt;/td&gt;
&lt;td&gt;41,405&lt;/td&gt;
&lt;td&gt;136,511&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;请求压缩次数&lt;/td&gt;
&lt;td&gt;16&lt;/td&gt;
&lt;td&gt;353&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;压缩节省 token&lt;/td&gt;
&lt;td&gt;622,160&lt;/td&gt;
&lt;td&gt;23,632,292&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;综合压缩率&lt;/td&gt;
&lt;td&gt;39.92%&lt;/td&gt;
&lt;td&gt;52.03%&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;平均压缩率&lt;/td&gt;
&lt;td&gt;41.1%&lt;/td&gt;
&lt;td&gt;38.2%&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;最佳压缩&lt;/td&gt;
&lt;td&gt;44.4%（97,688 → 54,280 tokens）&lt;/td&gt;
&lt;td&gt;88.1%（572,012 → 68,132 tokens）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;前缀冻结次数&lt;/td&gt;
&lt;td&gt;17&lt;/td&gt;
&lt;td&gt;103&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;前缀缓存命中率&lt;/td&gt;
&lt;td&gt;0.5%&lt;/td&gt;
&lt;td&gt;98.3%&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;请求缓存命中率&lt;/td&gt;
&lt;td&gt;42.9%&lt;/td&gt;
&lt;td&gt;97.1%&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;平均延迟&lt;/td&gt;
&lt;td&gt;31,973ms&lt;/td&gt;
&lt;td&gt;15,242ms&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;最大延迟&lt;/td&gt;
&lt;td&gt;217,235ms&lt;/td&gt;
&lt;td&gt;282,213ms&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;平均 overhead&lt;/td&gt;
&lt;td&gt;290.09ms&lt;/td&gt;
